export type LegaleseClauseKind =
  | 'definition'
  | 'user_obligation'
  | 'user_prohibition'
  | 'user_right'
  | 'provider_right'
  | 'provider_obligation'
  | 'limitation_of_liability'
  | 'dispute_resolution'
  | 'termination'
  | 'payment'
  | 'privacy_data'
  | 'content_license'
  | 'general';

export type LegaleseRiskKind =
  | 'unilateral_change'
  | 'termination_or_suspension'
  | 'liability_limit'
  | 'mandatory_arbitration'
  | 'jurisdiction_governing_law'
  | 'content_license'
  | 'payment_or_auto_renewal'
  | 'data_or_privacy'
  | 'third_party_dependency'
  | 'unclear_language';

export type LegaleseActor =
  | 'user'
  | 'provider'
  | 'third_party'
  | 'regulator'
  | 'both'
  | 'unknown';

export type LegaleseClarity = 'plain' | 'moderate' | 'hard' | 'opaque';

export type LegaleseSpanKind =
  | 'clause'
  | 'heading'
  | 'definition'
  | 'cross_reference'
  | 'condition'
  | 'exception'
  | 'frame'
  | 'hole';

export type LegaleseDeonticOperator =
  | 'may'
  | 'must'
  | 'must_not'
  | 'will'
  | 'can'
  | 'waives'
  | 'disclaims'
  | 'limits'
  | 'consents'
  | 'grants'
  | 'terminates'
  | 'changes'
  | 'collects'
  | 'shares'
  | 'pays'
  | 'refunds'
  | 'renews'
  | 'governs'
  | 'unknown';

export type LegaleseLegalAction =
  | 'change'
  | 'terminate'
  | 'suspend'
  | 'delete'
  | 'disclaim'
  | 'limit'
  | 'arbitrate'
  | 'waive'
  | 'grant_license'
  | 'collect'
  | 'share'
  | 'process'
  | 'pay'
  | 'charge'
  | 'refund'
  | 'renew'
  | 'govern'
  | 'choose_forum'
  | 'incorporate_document'
  | 'interpret'
  | 'unknown';

export type LegaleseLegalObject =
  | 'terms'
  | 'fees'
  | 'service'
  | 'account'
  | 'user_content'
  | 'personal_data'
  | 'liability'
  | 'warranty'
  | 'damages'
  | 'dispute'
  | 'jurisdiction'
  | 'law'
  | 'document'
  | 'feedback'
  | 'unknown';

export type LegaleseFrameHoleKind =
  | 'actor'
  | 'action'
  | 'object'
  | 'scope'
  | 'condition'
  | 'definition'
  | 'cross_reference'
  | 'exception';

export interface LegaleseSpan {
  kind: LegaleseSpanKind;
  startOffset: number;
  endOffset: number;
  text: string;
}

export interface LegaleseSection {
  id: string;
  index: number;
  path: string[];
  heading: string;
  startOffset: number;
  endOffset: number;
}

export interface LegaleseDefinition {
  id: string;
  term: string;
  meaning: string;
  span: LegaleseSpan;
}

export interface LegaleseCrossReference {
  id: string;
  rawText: string;
  target: string;
  span: LegaleseSpan;
  resolved: boolean;
  resolvedSectionId?: string;
  resolvedSectionPath?: string[];
}

export interface LegaleseFrameHole {
  id: string;
  kind: LegaleseFrameHoleKind;
  message: string;
  span: LegaleseSpan;
}

export interface LegaleseClauseFrame {
  id: string;
  riskKind: LegaleseRiskKind;
  actor: LegaleseActor;
  recipient: LegaleseActor;
  operator: LegaleseDeonticOperator;
  action: LegaleseLegalAction;
  object: LegaleseLegalObject;
  conditions: string[];
  exceptions: string[];
  scope: string[];
  evidenceSpans: LegaleseSpan[];
  holes: LegaleseFrameHole[];
  confidence: number;
}

export interface LegaleseLoweringOptions {
  documentId?: string;
  sourcePath?: string;
  serviceName?: string;
  maxClauses?: number;
  minClauseChars?: number;
  maxClauseChars?: number;
  excerptChars?: number;
}

export interface LegaleseClauseSignal {
  kind: LegaleseRiskKind | LegaleseClauseKind;
  confidence: number;
  pattern: string;
}

export interface LegaleseClauseLowering {
  id: string;
  index: number;
  text: string;
  excerpt: string;
  kind: LegaleseClauseKind;
  actor: LegaleseActor;
  risks: LegaleseRiskKind[];
  signals: LegaleseClauseSignal[];
  wordCount: number;
  sentenceCount: number;
  averageWordsPerSentence: number;
  legalTermCount: number;
  clarity: LegaleseClarity;
  clarityScore: number;
  sectionPath: string[];
  heading: string;
  spans: LegaleseSpan[];
  definitions: LegaleseDefinition[];
  crossReferences: LegaleseCrossReference[];
  frames: LegaleseClauseFrame[];
  holes: LegaleseFrameHole[];
}

export interface LegaleseLoweringSummary {
  documentId: string;
  serviceName: string;
  clauseCount: number;
  riskCounts: Record<LegaleseRiskKind, number>;
  hardClauseCount: number;
  opaqueClauseCount: number;
  averageWordsPerClause: number;
}

export interface LegaleseLoweringResult {
  ggSource: string;
  documentId: string;
  serviceName: string;
  clauses: LegaleseClauseLowering[];
  sections: LegaleseSection[];
  risks: LegaleseRiskKind[];
  summary: LegaleseLoweringSummary;
}

export interface LegaleseClauseSegment {
  text: string;
  startOffset: number;
  endOffset: number;
  sectionPath: string[];
  heading: string;
  blockIndex: number;
  sentenceIndex: number;
}

export interface LegaleseSegmentationResult {
  normalizedText: string;
  sections: LegaleseSection[];
  clauses: LegaleseClauseSegment[];
}

